import java.math.BigDecimal;
import org.apache.commons.math.linear.BigMatrix;
import org.apache.commons.math.linear.BigMatrixImpl;

public class TestRequirement {
    public static void main(String[] args) {
        try {
            // Given a BigMatrix with 3 rows and 2 columns initialized with:
            // | 1 | 2 |
            // | 3 | 4 |
            // | 5 | 6 |
            BigDecimal[][] matrixData = {
                {new BigDecimal("1"), new BigDecimal("2")},
                {new BigDecimal("3"), new BigDecimal("4")},
                {new BigDecimal("5"), new BigDecimal("6")}
            };
            BigMatrix matrix = new BigMatrixImpl(matrixData);

            // And a BigDecimal vector of length 2:
            // | 1 |
            // | 1 |
            BigDecimal[] vector = {new BigDecimal("1"), new BigDecimal("1")};

            // When the matrix operates on the vector
            BigDecimal[] result = matrix.operate(vector);

            // Then the result should be a vector of length 3
            if (result.length != 3) {
                System.out.println("FAIL: Result vector length is " + result.length + ", expected 3");
                return;
            }

            // And the result values should be:
            // | 3.0  |
            // | 7.0  |
            // | 11.0 |
            BigDecimal[] expected = {
                new BigDecimal("3.0"),
                new BigDecimal("7.0"),
                new BigDecimal("11.0")
            };

            boolean success = true;
            for (int i = 0; i < result.length; i++) {
                if (!result[i].equals(expected[i])) {
                    System.out.println("FAIL: At index " + i + ", got " + result[i] + ", expected " + expected[i]);
                    success = false;
                }
            }

            if (success) {
                System.out.println("PASS: All values match expected results");
            } else {
                System.out.println("FAIL: Some values don't match expected results");
            }
        } catch (Exception e) {
            System.out.println("ERROR: " + e.getMessage());
            e.printStackTrace();
        }
    }
}

